INSERT INTO legacy_mgmt.products (id, name, category, description, reference_link, attachment_url, is_active, base_closing_days, created_at, updated_at) VALUES ('1e23148a-af5c-410e-ba24-d3dd367372c7', 'Larksuite', 'Productivity & Collaboration Platform / Digital Workplace / Workflow & Operations Platform', 'Lark adalah platform kerja terpadu yang menggabungkan chat, meeting, kalender, dokumen, penyimpanan cloud, workflow automation, dan AI dalam satu ekosistem kerja. Nilai utamanya bukan hanya komunikasi tim, tetapi juga penyatuan proses kerja agar koordinasi, dokumentasi, pengambilan keputusan, dan eksekusi operasional dapat berjalan dalam satu platform yang saling terhubung. Untuk perusahaan, Lark relevan sebagai fondasi digital workplace modern yang mampu mengurangi silo antar aplikasi, mempercepat kolaborasi lintas divisi, dan mendukung pembuatan workflow operasional maupun dashboard kerja yang lebih terstruktur.', '', NULL, true, 30, '2026-04-14 14:10:05.96', '2026-04-14 14:10:05.96') ON CONFLICT DO NOTHING;
INSERT INTO legacy_mgmt.ai_parameter_suggestions (id, product_id, suggested_name, suggested_key, description, reasoning, status, created_at) VALUES ('7313175c-73f5-4f68-8e0a-09e4bbe28243', '1e23148a-af5c-410e-ba24-d3dd367372c7', 'Current Collaboration Tools', 'current_collaboration_tools', 'Existing tools and platforms used for team collaboration', 'Companies using multiple disjointed tools may seek an integrated solution like Lark to streamline their processes.', 'PENDING', '2026-04-14 14:27:30.172') ON CONFLICT DO NOTHING;
INSERT INTO legacy_mgmt.ai_parameter_suggestions (id, product_id, suggested_name, suggested_key, description, reasoning, status, created_at) VALUES ('ea9d4672-b862-49cf-81a7-1d10acbf26a5', '1e23148a-af5c-410e-ba24-d3dd367372c7', 'Workflow Automation Needs', 'workflow_automation_needs', 'The extent to which the company relies on automated workflows', 'Organizations looking to enhance efficiency through automation are prime candidates for Lark''s capabilities.', 'APPROVED', '2026-04-14 14:27:30.179') ON CONFLICT DO NOTHING;
INSERT INTO legacy_mgmt.ai_parameter_suggestions (id, product_id, suggested_name, suggested_key, description, reasoning, status, created_at) VALUES ('d81abd25-e03d-4e08-91b7-b8110623aa98', '1e23148a-af5c-410e-ba24-d3dd367372c7', 'Digital Transformation Initiatives', 'digital_transformation_initiatives', 'Ongoing or planned initiatives to modernize workplace technology', 'Companies actively pursuing digital transformation are more likely to invest in comprehensive solutions like Lark.', 'APPROVED', '2026-04-14 14:27:30.178') ON CONFLICT DO NOTHING;
INSERT INTO legacy_mgmt.ai_parameter_suggestions (id, product_id, suggested_name, suggested_key, description, reasoning, status, created_at) VALUES ('e573eae0-7bb6-402d-8000-b17698a0e137', '1e23148a-af5c-410e-ba24-d3dd367372c7', 'Team Size', 'team_size', 'Number of employees or teams that require collaboration', 'Larger teams often face more challenges in coordination and may benefit significantly from a unified platform.', 'APPROVED', '2026-04-14 14:27:30.177') ON CONFLICT DO NOTHING;
