INSERT INTO legacy_mgmt.lead_evaluations (id, lead_id, total_score, status, dimension_scores, reasoning, risk_flags, recommendation, recommended_product_id, confidence_score, estimated_closing_days, hard_stop_triggered, hard_stop_rule, evaluated_by, evaluated_at, is_latest, created_at) VALUES ('e404bfa5-bd4b-497e-a7dd-70da70191fcb', '1144dba7-087f-472e-91ca-3ebc14745325', 88.10, 'POTENTIAL', '[{"key": "firmographic", "name": "Firmographic Fit", "score": 11.67, "maxScore": 20, "rawScore": 35, "maxRawScore": 60}, {"key": "need_relevance", "name": "Need Relevance", "score": 21.43, "maxScore": 25, "rawScore": 60, "maxRawScore": 70}, {"key": "budget_commercial", "name": "Budget & Commercial Readiness", "score": 20, "maxScore": 20, "rawScore": 45, "maxRawScore": 45}, {"key": "stakeholder_access", "name": "Stakeholder Access", "score": 20, "maxScore": 20, "rawScore": 50, "maxRawScore": 50}, {"key": "technical_fit", "name": "Technical Fit", "score": 15, "maxScore": 15, "rawScore": 35, "maxRawScore": 35}]', '["+5: Company Size — 10–49 employees (Small)", "+20: Industry Match — Exact ICP match", "+10: Geography — Serviceable market", "+25: Problem Clarity — Clearly defined", "+15: Solution Alignment — Partial match", "+20: Urgency — Immediate (< 1 month)", "+20: Budget Status — Confirmed & allocated", "+15: Timeline — < 3 months", "+10: Procurement — Simple process", "+20: Decision Maker — Engaged & accessible", "+15: Champion — Internal champion exists", "+15: Engagement Level — Multiple touchpoints", "+20: Infrastructure — Modern cloud/SaaS", "+15: Integration Complexity — Simple API", "------ AI Analysis ------", "🤖 The lead has a clearly defined need for collaboration tools, indicating strong relevance for Lark.", "🤖 The urgency for implementation is immediate, suggesting a high likelihood of a quick decision.", "🤖 The budget status is confirmed and allocated, which supports a favorable purchasing decision.", "🤖 While the industry match is exact, the company size does not fully align with the ideal customer profile, which may require further exploration."]', '[]', '🤖 AI Generated: Menara Rajawali shows a strong interest in adopting collaboration tools, making Lark a relevant solution for their needs. The company has a clearly defined problem and an immediate urgency for implementation, which aligns well with Lark''s capabilities as a productivity and collaboration platform. However, the firmographic fit indicates a slight mismatch in company size, which may require further discussion to ensure Lark can fully meet their needs. The next steps should involve a deeper engagement with the decision-makers to explore their specific requirements and demonstrate how Lark can address their collaboration challenges effectively.', '1e23148a-af5c-410e-ba24-d3dd367372c7', 75, 30, false, NULL, '072db61f-4708-44c7-8e3d-f06de866de31', '2026-04-17 02:33:02.106', true, '2026-04-17 02:33:02.106') ON CONFLICT DO NOTHING;
INSERT INTO legacy_mgmt.lead_activities (id, lead_id, user_id, type, title, description, metadata, created_at) VALUES ('46390288-ca9e-42d3-8427-a24e5004f46d', '1144dba7-087f-472e-91ca-3ebc14745325', '072db61f-4708-44c7-8e3d-f06de866de31', 'EVALUATION', 'Lead evaluated: POTENTIAL (Score: 88.1)', '🤖 AI Generated: Menara Rajawali shows a strong interest in adopting collaboration tools, making Lark a relevant solution for their needs. The company has a clearly defined problem and an immediate urgency for implementation, which aligns well with Lark''s capabilities as a productivity and collaboration platform. However, the firmographic fit indicates a slight mismatch in company size, which may require further discussion to ensure Lark can fully meet their needs. The next steps should involve a deeper engagement with the decision-makers to explore their specific requirements and demonstrate how Lark can address their collaboration challenges effectively.', '{"score": 88.1, "status": "POTENTIAL"}', '2026-04-17 02:33:02.119') ON CONFLICT DO NOTHING;
