INSERT INTO public.products (id, name, category, description, target_industry, target_pain_points, target_buyer_persona, ideal_company_profile, ai_reference_material, status, created_by, created_at, updated_at, tenant_id, supported_regions, budget_range, target_company_size, use_cases, competitor_notes, keywords) VALUES (11, 'Lark Collaboration & Operations Platform', 'Productivity & Collaboration Software, Customer Engagement & Communication Platform', 'Lark Collaboration & Operations Platform is a comprehensive tool designed to enhance productivity and streamline operations for businesses. It provides features such as chat, video conferencing, and task management, helping teams collaborate efficiently across various industries, including technology and logistics.', 'Technology & IT Services, Logistics & Transportation', 'Inefficient team communication
INSERT INTO public.products (id, name, category, description, target_industry, target_pain_points, target_buyer_persona, ideal_company_profile, ai_reference_material, status, created_by, created_at, updated_at, tenant_id, supported_regions, budget_range, target_company_size, use_cases, competitor_notes, keywords) VALUES (15, 'Mekari Qontak Omnichannel CRM', 'Customer Engagement & CRM Software, Customer Engagement & Communication Platform', 'Mekari Qontak Omnichannel CRM is an integrated customer relationship management platform designed to enhance customer engagement and streamline communication across multiple channels. It helps businesses in Indonesia improve customer interaction, boost sales efficiency, and drive business growth.', 'Retail & Distribution, Technology & IT Services, Finance & Banking', 'Disjointed customer communication channels
