INSERT INTO public.geo_product_fit_analyses (id, place_id, product_id, lead_id, fit_score, fit_level, confidence_score, reasoning, matched_signals, missing_information, risk_flags, recommended_approach, recommended_next_action, potential_use_case, pre_fit_score, analyzed_with_ai, ai_provider_used, ai_model_used, source_payload_hash, product_payload_hash, analyzed_at, created_by, created_at, updated_at) VALUES (221, 'ChIJkw0Gzi30aS4R2dWuESjgC40', 11, NULL, 45, 'low', 40, '["Location matches the supported region of Indonesia.","Industry relevance is unclear as LPSE Provinsi DKI Jakarta is not directly in technology or logistics.","No clear indication of company size or operational scale."]', '["Supported region: Indonesia"]', '["Industry type","Company size","Operational maturity indicators"]', '["Lack of business scale information","Unclear alignment with target industry"]', 'Investigate further to identify the business''s operational scale and industry type.', 'Contact the business to gather more information about their operations, size, and any current tools for collaboration.', 'Enhancing remote team collaboration', 3, true, NULL, 'gpt-4o', '606e5e45f74d63b040a6c4aeb25ac5184f6154d324c6221d21b613cbc3c5ccfb', 'd8d3738ceed3f0c958be0bcad592569e8ebb463543b41bc8b3f6da3c40d61a9b', '2026-05-17 15:29:33', 1, '2026-05-17 15:27:39', '2026-05-17 15:29:33') ON CONFLICT DO NOTHING;
INSERT INTO public.geo_product_fit_analyses (id, place_id, product_id, lead_id, fit_score, fit_level, confidence_score, reasoning, matched_signals, missing_information, risk_flags, recommended_approach, recommended_next_action, potential_use_case, pre_fit_score, analyzed_with_ai, ai_provider_used, ai_model_used, source_payload_hash, product_payload_hash, analyzed_at, created_by, created_at, updated_at) VALUES (224, 'ChIJBY1VZi70aS4RptT0hjU7vmg', 11, NULL, 35, 'unknown', 40, '["The business category is not clearly aligned with the target industries of technology, IT services, or logistics.","Located in Indonesia, which is a supported region.","No clear indication of the business scale such as employee count or web presence."]', '["Location fits the supported region"]', '["Target industry alignment","Company size or employee count","Web presence or digital maturity indicators"]', '["Unclear industry fit","Lack of digital presence"]', 'Verify industry and business scale through direct contact.', 'Reach out to gather more information about the business’s operations and potential fit.', 'Enhancing remote team collaboration', 3, true, NULL, 'gpt-4o', '5e2beb54d9e7d2033099cbc81c4054aebb66053d4e47822b35f26f860a275039', 'd8d3738ceed3f0c958be0bcad592569e8ebb463543b41bc8b3f6da3c40d61a9b', '2026-05-17 15:29:44', 1, '2026-05-17 15:27:39', '2026-05-17 15:29:44') ON CONFLICT DO NOTHING;
INSERT INTO public.geo_product_fit_analyses (id, place_id, product_id, lead_id, fit_score, fit_level, confidence_score, reasoning, matched_signals, missing_information, risk_flags, recommended_approach, recommended_next_action, potential_use_case, pre_fit_score, analyzed_with_ai, ai_provider_used, ai_model_used, source_payload_hash, product_payload_hash, analyzed_at, created_by, created_at, updated_at) VALUES (227, 'ChIJF5FDCS70aS4RrCW4i4HkHvE', 11, NULL, 35, 'unknown', 45, '["The business category is not aligned with the target industries of technology and logistics.","Located in Indonesia, which matches the supported region requirement.","Limited signals about the business scale and digital maturity due to lack of website or size indicators."]', '["Located in supported region (Indonesia)"]', '["Industry relevance","Company size","Digital maturity indicators (e.g., website)"]', '["Potential mismatch in industry","Lack of digital presence and scale signals"]', 'Consider reaching out only if more information about industry relevance or company size can be gathered.', 'Research industry focus and organizational size to determine potential fit.', 'Unknown due to lack of detailed information.', 3, true, NULL, 'gpt-4o', 'f0ed406ce5eb4e7624719775533ba295303803ee350e1f27bd3dbd129e7ee7c0', 'd8d3738ceed3f0c958be0bcad592569e8ebb463543b41bc8b3f6da3c40d61a9b', '2026-05-17 15:29:53', 1, '2026-05-17 15:27:39', '2026-05-17 15:29:53') ON CONFLICT DO NOTHING;
INSERT INTO public.geo_product_fit_analyses (id, place_id, product_id, lead_id, fit_score, fit_level, confidence_score, reasoning, matched_signals, missing_information, risk_flags, recommended_approach, recommended_next_action, potential_use_case, pre_fit_score, analyzed_with_ai, ai_provider_used, ai_model_used, source_payload_hash, product_payload_hash, analyzed_at, created_by, created_at, updated_at) VALUES (217, 'ChIJj4tXtQP3aS4R4eQg5oTlzw4', 11, NULL, 30, 'unknown', 30, '["No clear indication of industry alignment; business category is not directly related to target industries.","Location fit is possible, given Indonesia is a supported region.","Lacks digital presence; no website or phone details, indicating low digital maturity."]', '["Supported region: Indonesia"]', '["Industry alignment","Company size","Website or digital presence"]', '["Insufficient industry information","Unknown company size and buyer persona alignment"]', 'General awareness campaign focused on benefits of enhanced collaboration.', 'Research additional information about PT. Anta Tirta Kirana''s industry and size.', 'Enhancing remote team collaboration, if the business size and operations support it.', 3, true, NULL, 'gpt-4o', 'ca29ad12a67ffad40a40a3057c09f17201c1e8f21cfde588838c41dc138f088d', 'd8d3738ceed3f0c958be0bcad592569e8ebb463543b41bc8b3f6da3c40d61a9b', '2026-05-17 15:50:16', 1, '2026-05-17 15:26:07', '2026-05-17 15:50:16') ON CONFLICT DO NOTHING;
INSERT INTO public.geo_product_fit_analyses (id, place_id, product_id, lead_id, fit_score, fit_level, confidence_score, reasoning, matched_signals, missing_information, risk_flags, recommended_approach, recommended_next_action, potential_use_case, pre_fit_score, analyzed_with_ai, ai_provider_used, ai_model_used, source_payload_hash, product_payload_hash, analyzed_at, created_by, created_at, updated_at) VALUES (259, 'ChIJDx9FAzL0aS4RSVAGO0bkK_g', 11, NULL, 25, 'unknown', 40, '["The business is categorized as an embassy, which falls outside the target industries of technology and logistics.","There is no information available on company size, web presence, or specific operational needs that align with Lark''s use cases.","The diplomatic nature of the embassy suggests different communication needs and budget priorities not directly addressed by Lark''s ICP."]', '["Located in Indonesia"]', '["Company size","Presence of typical buyer personas such as CTO or Operations Manager","Budget availability","Specific operational or digital maturity indicators"]', '["Misalignment of industry focus","Unknown scale and budget constraints"]', 'Given the weak fit, direct outreach is not recommended. Instead, focus on businesses with closer industry alignment.', 'Seek more information on industry-neutral collaboration needs or potential introductions via government outreach programs.', 'Enhancing remote team collaboration', 3, true, NULL, 'gpt-4o', '3302ab4f9fa3573bc7973bdbc7c880dacda86a37441c47750c91b94734ac4c5f', 'd8d3738ceed3f0c958be0bcad592569e8ebb463543b41bc8b3f6da3c40d61a9b', '2026-05-17 15:27:46', 1, '2026-05-17 15:27:46', '2026-05-17 15:27:46') ON CONFLICT DO NOTHING;
