INSERT INTO public.geo_product_fit_analyses (id, place_id, product_id, lead_id, fit_score, fit_level, confidence_score, reasoning, matched_signals, missing_information, risk_flags, recommended_approach, recommended_next_action, potential_use_case, pre_fit_score, analyzed_with_ai, ai_provider_used, ai_model_used, source_payload_hash, product_payload_hash, analyzed_at, created_by, created_at, updated_at) VALUES (260, 'ChIJZSJ1hb_1aS4RaRAeC_1STJQ', 11, NULL, 42, 'low', 50, '["The industry category ''bank, atm, finance'' does not match the target industries of ''Technology & IT Services, Logistics & Transportation''.","Located in Indonesia, which aligns with the supported regions.","Lack of digital presence as there is no website or phone number provided, indicating potentially low digital\/operational maturity.","The specific roles of Chief Technology Officer, Operations Manager, or Project Manager are less likely in a banking branch context."]', '["Supported region (Indonesia)"]', '["Company size","Digital presence details (website, phone)"]', '["Non-aligned industry sector","No digital presence"]', 'General outreach to understand communication tools currently in use and challenges faced in operations.', 'Identify a contact in the IT department of the main Bank Mandiri office for a more relevant discussion.', 'Facilitating virtual meetings to improve communication between different branches.', 3, true, NULL, 'gpt-4o', 'c8b5dcbbaf7d0c9d4470c584c77cee35bda8379ce44a3da22b50989400066a23', 'd8d3738ceed3f0c958be0bcad592569e8ebb463543b41bc8b3f6da3c40d61a9b', '2026-05-17 15:27:49', 1, '2026-05-17 15:27:49', '2026-05-17 15:27:49') ON CONFLICT DO NOTHING;
INSERT INTO public.geo_product_fit_analyses (id, place_id, product_id, lead_id, fit_score, fit_level, confidence_score, reasoning, matched_signals, missing_information, risk_flags, recommended_approach, recommended_next_action, potential_use_case, pre_fit_score, analyzed_with_ai, ai_provider_used, ai_model_used, source_payload_hash, product_payload_hash, analyzed_at, created_by, created_at, updated_at) VALUES (261, 'ChIJZd_7Lyz0aS4R1Tpt2YnzwQs', 11, NULL, 45, 'low', 40, '["Industry\/category mismatch: The business is in the banking and finance sector, which does not align with the target industries of Technology & IT Services or Logistics & Transportation.","Location fit: The business is located in Indonesia, which matches the supported regions.","Lack of digital\/operational signals: The absence of a website and other digital presence indicators limits the assessment of digital\/operational maturity."]', '["Location fit"]', '["Company size","Website presence","Pain points specific to this business"]', '["Industry-category misalignment","Limited digital presence"]', 'If a similar opportunity arises within more aligned sectors, directly target roles like CTO or Operations Manager.', 'Research more about this specific business and similar entities to identify potential alignment opportunities in operations.', 'Enhancing remote team collaboration might be relevant if such needs exist within the banking operations.', 3, true, NULL, 'gpt-4o', '37793f783821c59e0d60ad558535dec9dd7b382c1613af901c4dfe04dfce0560', 'd8d3738ceed3f0c958be0bcad592569e8ebb463543b41bc8b3f6da3c40d61a9b', '2026-05-17 15:27:53', 1, '2026-05-17 15:27:53', '2026-05-17 15:27:53') ON CONFLICT DO NOTHING;
INSERT INTO public.geo_product_fit_analyses (id, place_id, product_id, lead_id, fit_score, fit_level, confidence_score, reasoning, matched_signals, missing_information, risk_flags, recommended_approach, recommended_next_action, potential_use_case, pre_fit_score, analyzed_with_ai, ai_provider_used, ai_model_used, source_payload_hash, product_payload_hash, analyzed_at, created_by, created_at, updated_at) VALUES (262, 'ChIJie2Vzi30aS4RC_g5alu9Aq0', 11, NULL, 45, 'low', 50, '["Industry\/category mismatch: Business is a non-profit foundation, not matching target industries.","Location fit: Business is located in Indonesia, which matches the supported region.","Lack of web presence makes it difficult to assess digital operations maturity and business scale."]', '["Supported region: Indonesia"]', '["Business website","Company size","Phone number"]', '["Potential for limited budget as a non-profit","Possible mismatch in industry needs"]', 'Consider reaching out with an emphasis on exploring collaboration benefits tailored for non-profit organizations.', 'Research more about the organization''s structure and potential budget to better understand their fit.', 'Enhancing remote team collaboration, if applicable in a non-profit context', 3, true, NULL, 'gpt-4o', 'a925f6f56e4f767710bf8369fe7b602357c2f710d1d777dcf36ee7e2852ac391', 'd8d3738ceed3f0c958be0bcad592569e8ebb463543b41bc8b3f6da3c40d61a9b', '2026-05-17 15:27:56', 1, '2026-05-17 15:27:56', '2026-05-17 15:27:56') ON CONFLICT DO NOTHING;
INSERT INTO public.geo_product_fit_analyses (id, place_id, product_id, lead_id, fit_score, fit_level, confidence_score, reasoning, matched_signals, missing_information, risk_flags, recommended_approach, recommended_next_action, potential_use_case, pre_fit_score, analyzed_with_ai, ai_provider_used, ai_model_used, source_payload_hash, product_payload_hash, analyzed_at, created_by, created_at, updated_at) VALUES (263, 'ChIJwdI3AS70aS4R8vnGKQfA_Mo', 11, NULL, 35, 'unknown', 40, '["The discovered business is a governmental entity, not aligned with the target industries of Technology or Logistics.","Lack of information regarding company size, digital presence, or typical roles which could align with the buyer persona.","No available website or clear indication of digital\/operational maturity."]', '["Location fit: Indonesia"]', '["Industry relevance","Company size","Digital presence","Budget indication"]', '["Non-commercial and governmental focus","Lack of digital footprint"]', 'Low priority for outreach; not the primary market for the product.', 'Explore other businesses within the target industries with better fit signals.', 'Not applicable due to weak alignment', 3, true, NULL, 'gpt-4o', '11360100805efa0d6b5d75efa09831dbd804259b9dde612c906bef25773c7d39', 'd8d3738ceed3f0c958be0bcad592569e8ebb463543b41bc8b3f6da3c40d61a9b', '2026-05-17 15:28:00', 1, '2026-05-17 15:28:00', '2026-05-17 15:28:00') ON CONFLICT DO NOTHING;
INSERT INTO public.geo_product_fit_analyses (id, place_id, product_id, lead_id, fit_score, fit_level, confidence_score, reasoning, matched_signals, missing_information, risk_flags, recommended_approach, recommended_next_action, potential_use_case, pre_fit_score, analyzed_with_ai, ai_provider_used, ai_model_used, source_payload_hash, product_payload_hash, analyzed_at, created_by, created_at, updated_at) VALUES (264, 'ChIJiyqJ_Bz0aS4Rqpd7X1S9LeQ', 11, NULL, 45, 'low', 30, '["The business category ''point_of_interest, establishment'' does not directly align with the target industries of Technology & IT Services or Logistics & Transportation.","There is no available information on company size or a web presence to infer the scale or budget.","The absence of any specified roles like CTO, Operations Manager, or Project Manager reduces the likelihood of a strong buyer persona match."]', '["Location is within Indonesia, a supported region."]', '["Company size","Industry category"]', '["Limited available data","No web presence indicating potential digital immaturity"]', 'Conduct further research to identify the industry and scale of PT. Administrasi Medika.', 'Reach out to local business directories or networks to gather more information about PT. Administrasi Medika.', 'Facilitating virtual meetings if they use basic communication software.', 3, true, NULL, 'gpt-4o', '78eb632cc78487d559ba1d565cb50021504941272aa43529fae83dbf1e36d3e5', 'd8d3738ceed3f0c958be0bcad592569e8ebb463543b41bc8b3f6da3c40d61a9b', '2026-05-17 15:28:04', 1, '2026-05-17 15:28:04', '2026-05-17 15:28:04') ON CONFLICT DO NOTHING;
