INSERT INTO public.geo_product_fit_analyses (id, place_id, product_id, lead_id, fit_score, fit_level, confidence_score, reasoning, matched_signals, missing_information, risk_flags, recommended_approach, recommended_next_action, potential_use_case, pre_fit_score, analyzed_with_ai, ai_provider_used, ai_model_used, source_payload_hash, product_payload_hash, analyzed_at, created_by, created_at, updated_at) VALUES (307, 'ChIJsRkaoXDQQC4RX-eaY2aXGVQ', 11, NULL, 25, 'unknown', 40, '["Industry\/category of business does not match the target industry of Technology & IT Services or Logistics & Transportation.","The business is located in Indonesia, which fits the supported regions.","The typical operations of a hotel do not align with the identified use cases of enhancing remote team collaboration or centralizing project management tasks."]', '["Located in supported region"]', '["Number of employees","Website presence","Buyer persona likelihood","Budget information"]', '["Misalignment with target industry","Lack of detailed business information"]', 'Given the weak fit, it is advisable to deprioritize this lead or investigate further into potential digital transformation projects within the hotel for specific opportunities.', 'Identify and target businesses that fit the Technology or Logistics industry more closely.', 'Facilitating virtual meetings, if they conduct business conferences or events.', 3, true, NULL, 'gpt-4o', 'd11bc8501f2b4b29285e4c5675c546e3696ad8fb0c066458c2ce964fea6480b5', 'd8d3738ceed3f0c958be0bcad592569e8ebb463543b41bc8b3f6da3c40d61a9b', '2026-05-17 15:32:22', 1, '2026-05-17 15:32:22', '2026-05-17 15:32:22') ON CONFLICT DO NOTHING;
INSERT INTO public.geo_product_fit_analyses (id, place_id, product_id, lead_id, fit_score, fit_level, confidence_score, reasoning, matched_signals, missing_information, risk_flags, recommended_approach, recommended_next_action, potential_use_case, pre_fit_score, analyzed_with_ai, ai_provider_used, ai_model_used, source_payload_hash, product_payload_hash, analyzed_at, created_by, created_at, updated_at) VALUES (308, 'ChIJrSx5VT70aS4RLBp6NXspgWk', 11, NULL, 30, 'unknown', 50, '["The business category ''lodging'' does not align with the target industries of Technology & IT Services or Logistics & Transportation.","The business is located in Indonesia, which matches the supported regions.","There is no available information on the business''s size or presence of buyer personas relevant to the Lark platform."]', '["Supported region: Indonesia"]', '["Company size","Presence of target buyer personas","Website"]', '["Misalignment with target industry","Unknown business scale"]', 'No immediate sales approach due to weak product-fit assessment.', 'Research more details about the business scale and operational maturity if feasible.', 'Enhancing remote team collaboration', 3, true, NULL, 'gpt-4o', '3352db2ada3cd289be2de62414dd5ddaa9236a3608ecae0e8baba36b93d3d744', 'd8d3738ceed3f0c958be0bcad592569e8ebb463543b41bc8b3f6da3c40d61a9b', '2026-05-17 15:32:25', 1, '2026-05-17 15:32:25', '2026-05-17 15:32:25') ON CONFLICT DO NOTHING;
INSERT INTO public.geo_product_fit_analyses (id, place_id, product_id, lead_id, fit_score, fit_level, confidence_score, reasoning, matched_signals, missing_information, risk_flags, recommended_approach, recommended_next_action, potential_use_case, pre_fit_score, analyzed_with_ai, ai_provider_used, ai_model_used, source_payload_hash, product_payload_hash, analyzed_at, created_by, created_at, updated_at) VALUES (309, 'ChIJY3RzpBX0aS4RikHOJaUxspQ', 11, NULL, 37, 'unknown', 50, '["The Hermitage, a Tribute Portfolio Hotel, Jakarta is in the lodging industry, not the target industries of Technology or Logistics.","The location is in Indonesia, which fits the supported regions.","As a hotel, the likelihood of needing collaboration tools is lower compared to tech firms; operational tasks are more guest-focused."]', '["Location in Indonesia"]', '["Company size","Website information"]', '["Misalignment with target industry","Lack of digital\/operational maturity indicators"]', 'Due to the low fit, direct selling is not recommended. Monitor for any expansions or pivots towards tech/logistics sectors.', 'Conduct an assessment of similar-sized hotels that might benefit from operational tools.', 'Facilitating virtual meetings for remote corporate clients if applicable.', 3, true, NULL, 'gpt-4o', '5aa668b7582aef0914c7d096d512523163cd32f6fb644c10ca817855167adc37', 'd8d3738ceed3f0c958be0bcad592569e8ebb463543b41bc8b3f6da3c40d61a9b', '2026-05-17 15:32:28', 1, '2026-05-17 15:32:28', '2026-05-17 15:32:28') ON CONFLICT DO NOTHING;
INSERT INTO public.geo_product_fit_analyses (id, place_id, product_id, lead_id, fit_score, fit_level, confidence_score, reasoning, matched_signals, missing_information, risk_flags, recommended_approach, recommended_next_action, potential_use_case, pre_fit_score, analyzed_with_ai, ai_provider_used, ai_model_used, source_payload_hash, product_payload_hash, analyzed_at, created_by, created_at, updated_at) VALUES (310, 'ChIJgf5Bpj70aS4RiXRscJ_r2X0', 11, NULL, 20, 'unknown', 30, '["The business category ''point_of_interest, establishment'' does not align with the target industry of ''Technology & IT Services, Logistics & Transportation''.","No website or phone information is available to assess digital maturity or scale.","Location matches supported region (Indonesia) but other signals are missing."]', '["Location is in a supported region."]', '["Industry\/category relevance","Company size","Digital maturity indicators like website or web presence","Specific pain points"]', '["Insufficient information to determine product-market fit","No clear indication of relevant buyer personas"]', 'Conduct further research to identify if this business houses companies that match the ICP.', 'Research if there are any technology or logistics businesses within Gedung Arva Gondangdia that might fit the ICP.', 'Unknown due to lack of detailed business information', 3, true, NULL, 'gpt-4o', '03fe862513687d9e22a9452efc7841a2cb4690c68e32b10a743ad78033f530bc', 'd8d3738ceed3f0c958be0bcad592569e8ebb463543b41bc8b3f6da3c40d61a9b', '2026-05-17 15:32:32', 1, '2026-05-17 15:32:32', '2026-05-17 15:32:32') ON CONFLICT DO NOTHING;
