INSERT INTO public.geo_product_fit_analyses (id, place_id, product_id, lead_id, fit_score, fit_level, confidence_score, reasoning, matched_signals, missing_information, risk_flags, recommended_approach, recommended_next_action, potential_use_case, pre_fit_score, analyzed_with_ai, ai_provider_used, ai_model_used, source_payload_hash, product_payload_hash, analyzed_at, created_by, created_at, updated_at) VALUES (312, 'ChIJ52CdWTn0aS4RU-35RDjHKT4', 11, NULL, 30, 'unknown', 20, '["Lack of specific industry\/category relevance to Technology, IT Services, or Logistics.","No available data on business size or digital maturity, making it hard to infer budget or scale.","Absence of website or digital presence limits understanding of business operations and potential pain points."]', '["Business address is located in Indonesia, which matches supported regions."]', '["Target industry category of the business","Company size or number of employees","Pain points or operational challenges"]', '["No web presence","Unknown company size or industry alignment"]', 'Due to the lack of clear fit signals, a broad exploratory outreach focusing on discovering company details may be warranted.', 'Conduct a preliminary research call to ascertain the business''s industry, size, and potential need for collaboration tools.', 'Unknown due to insufficient data.', 3, true, NULL, 'gpt-4o', 'fa55897b0fab65310cf3653588fb665b6b6da423c3d3915e5c70270ee1475432', 'd8d3738ceed3f0c958be0bcad592569e8ebb463543b41bc8b3f6da3c40d61a9b', '2026-05-17 15:32:38', 1, '2026-05-17 15:32:38', '2026-05-17 15:32:38') ON CONFLICT DO NOTHING;
