INSERT INTO public.geo_product_fit_analyses (id, place_id, product_id, lead_id, fit_score, fit_level, confidence_score, reasoning, matched_signals, missing_information, risk_flags, recommended_approach, recommended_next_action, potential_use_case, pre_fit_score, analyzed_with_ai, ai_provider_used, ai_model_used, source_payload_hash, product_payload_hash, analyzed_at, created_by, created_at, updated_at) VALUES (214, 'ChIJDZmifAb3aS4R99V4SI0kV6A', 11, NULL, 35, 'unknown', 40, '["The business is a furniture and home goods store, which does not align with the targeted industries of technology or logistics.","Located in Indonesia, it fits the regional criteria.","There is a lack of relevant digital presence and scale indicators to assess the operational size and maturity."]', '["Location fit with supported regions"]', '["Website presence","Company size","Relevant personnel roles"]', '["Misalignment with target industry","Insufficient data to determine digital maturity"]', 'Conduct further research to verify the business size and roles before outreach.', 'Attempt to obtain contact information and verify business scale and operational needs.', 'Unknown, due to lack of relevant industry alignment', 3, true, NULL, 'gpt-4o', '708b276adbbe36a51b029cbe642652cee04b54671634ae80e0364bc524473740', 'd8d3738ceed3f0c958be0bcad592569e8ebb463543b41bc8b3f6da3c40d61a9b', '2026-05-17 15:49:59', 1, '2026-05-17 15:26:07', '2026-05-17 15:49:59') ON CONFLICT DO NOTHING;
INSERT INTO public.geo_product_fit_analyses (id, place_id, product_id, lead_id, fit_score, fit_level, confidence_score, reasoning, matched_signals, missing_information, risk_flags, recommended_approach, recommended_next_action, potential_use_case, pre_fit_score, analyzed_with_ai, ai_provider_used, ai_model_used, source_payload_hash, product_payload_hash, analyzed_at, created_by, created_at, updated_at) VALUES (216, 'ChIJ9xT2K6z3aS4Rg0gpfOm_o-E', 11, NULL, 25, 'unknown', 30, '["Industry\/category mismatch with target industries","Lack of digital presence signals lower operational maturity","Unclear organizational roles aligning with target buyer personas"]', '["Supported region (Indonesia)"]', '["Company size","Website","Contact person details"]', '["Industry\/category mismatch","Limited digital presence"]', 'Research further into church operations to identify potential role relevant to buyer personas', 'Gather more information on the church''s operational structure and technology use', 'Facilitating virtual meetings', 3, true, NULL, 'gpt-4o', '56ba7ef5a5c7eea6322db67c01ac19b731794b2b6f86c24d2dfd95cbef4cb35a', 'd8d3738ceed3f0c958be0bcad592569e8ebb463543b41bc8b3f6da3c40d61a9b', '2026-05-17 15:50:12', 1, '2026-05-17 15:26:07', '2026-05-17 15:50:12') ON CONFLICT DO NOTHING;
INSERT INTO public.geo_product_fit_analyses (id, place_id, product_id, lead_id, fit_score, fit_level, confidence_score, reasoning, matched_signals, missing_information, risk_flags, recommended_approach, recommended_next_action, potential_use_case, pre_fit_score, analyzed_with_ai, ai_provider_used, ai_model_used, source_payload_hash, product_payload_hash, analyzed_at, created_by, created_at, updated_at) VALUES (218, 'ChIJ7dZvHbP3aS4Rc6_lBpJEwtM', 11, NULL, 35, 'unknown', 40, '["Industry\/category relevance is poor as the business is not clearly aligned with Technology & IT Services or Logistics & Transportation.","Location is in Indonesia, which is a supported region.","Limited available information on the company''s scale and operations suggests difficulty in identifying pain points or buyer personas."]', '["Location in Indonesia"]', '["Industry details","Company size","Web presence details"]', '["Low rating","No website or digital presence"]', 'General outreach to gather more information about their industry and operational scale.', 'Reach out to obtain more details about their industry and operations.', 'Not easily identifiable due to lack of information.', 3, true, NULL, 'gpt-4o', '376911559faa0de17766bdfad3cb000f7f1e1d1ad1aaf49125e7ef9fe136068a', 'd8d3738ceed3f0c958be0bcad592569e8ebb463543b41bc8b3f6da3c40d61a9b', '2026-05-17 15:50:20', 1, '2026-05-17 15:26:07', '2026-05-17 15:50:20') ON CONFLICT DO NOTHING;
INSERT INTO public.geo_product_fit_analyses (id, place_id, product_id, lead_id, fit_score, fit_level, confidence_score, reasoning, matched_signals, missing_information, risk_flags, recommended_approach, recommended_next_action, potential_use_case, pre_fit_score, analyzed_with_ai, ai_provider_used, ai_model_used, source_payload_hash, product_payload_hash, analyzed_at, created_by, created_at, updated_at) VALUES (219, 'ChIJS_gzQbH3aS4Ripujxn7bVwE', 11, NULL, 42, 'low', 55, '["The business is in the finance industry, which is not directly aligned with the target industries of technology or logistics.","Located in Jakarta, Indonesia, which fits within the supported region.","The lack of a website or detailed digital presence suggests lower digital operational maturity."]', '["Location fit with supported region","Potential need for enhanced team communication and operations"]', '["Company size","Detailed business operations or pain points"]', '["Unknown company size","Unclear buyer persona"]', 'Utilize a discovery call to understand their operational challenges and see if there is a direct need for enhanced collaboration or productivity solutions.', 'Conduct further research to determine business scale and decision-makers.', 'Enhancing remote team collaboration', 3, true, NULL, 'gpt-4o', 'ef53c2d723a485b473502962b5198012aca1658087a1960de5a0f5aa8e5b7ec0', 'd8d3738ceed3f0c958be0bcad592569e8ebb463543b41bc8b3f6da3c40d61a9b', '2026-05-17 15:50:24', 1, '2026-05-17 15:26:07', '2026-05-17 15:50:24') ON CONFLICT DO NOTHING;
INSERT INTO public.geo_product_fit_analyses (id, place_id, product_id, lead_id, fit_score, fit_level, confidence_score, reasoning, matched_signals, missing_information, risk_flags, recommended_approach, recommended_next_action, potential_use_case, pre_fit_score, analyzed_with_ai, ai_provider_used, ai_model_used, source_payload_hash, product_payload_hash, analyzed_at, created_by, created_at, updated_at) VALUES (170, 'ChIJj4XmALf3aS4RmQgs6FSrK-I', 11, NULL, 45, 'low', 45, '["Business location matches supported region (Indonesia).","Insufficient information on industry relevance; listed as ''point_of_interest, establishment'', which lacks clarity.","Lack of web presence and a specific industry indication reduces signals of digital maturity and scale."]', '["Location relevance to Indonesia"]', '["Industry relevance","Company size","Specific role titles (buyer personas)"]', '["Unclear industry fit","No web presence indicating lower digital maturity"]', 'Investigate further to determine the specific industry and confirm company size.', 'Reach out for a discovery call to learn about their industry and operations.', 'Enhancing remote team collaboration', 3, true, NULL, 'gpt-4o', 'b60f85a99a5b1a5dc026d19f8f0ebf1a5330601e893faef23abc8c32ef6ec0be', 'd8d3738ceed3f0c958be0bcad592569e8ebb463543b41bc8b3f6da3c40d61a9b', '2026-05-17 23:19:10', 1, '2026-05-17 15:26:07', '2026-05-17 23:19:10') ON CONFLICT DO NOTHING;
INSERT INTO public.geo_product_fit_analyses (id, place_id, product_id, lead_id, fit_score, fit_level, confidence_score, reasoning, matched_signals, missing_information, risk_flags, recommended_approach, recommended_next_action, potential_use_case, pre_fit_score, analyzed_with_ai, ai_provider_used, ai_model_used, source_payload_hash, product_payload_hash, analyzed_at, created_by, created_at, updated_at) VALUES (171, 'ChIJs7i2trb3aS4RKTkXC6ceAuQ', 11, NULL, 45, 'low', 50, '["Industry\/category mismatch: PT Dutaflow Hidrolik''s industry does not directly align with the technology & IT services, logistics & transportation industries targeted by Lark.","Unknown company size: Lack of information on the number of employees makes it difficult to assess the scale and potential budget alignment.","Location match: The business is in Indonesia, a supported region, which is a positive signal."]', '["Location match: Indonesia"]', '["Industry category","Company size","Digital presence (website)","Contact information"]', '["Inadequate industry alignment","Insufficient business scale data"]', 'Conduct further research to identify the company''s industry and size. If relevant, explore the potential to address communication and collaboration needs.', 'Reach out via phone or email to gather more information about the company''s industry and operational scale.', 'Enhancing remote team collaboration', 3, true, NULL, 'gpt-4o', 'fe0a6183e856321a48253aea5c1d7cb6b68e5040866a5f27d754c9ecb5d87c74', 'd8d3738ceed3f0c958be0bcad592569e8ebb463543b41bc8b3f6da3c40d61a9b', '2026-05-17 23:19:13', 1, '2026-05-17 15:26:07', '2026-05-17 23:19:13') ON CONFLICT DO NOTHING;
INSERT INTO public.icp_profiles (id, name, description, target_industries, target_company_sizes, target_territories, min_lead_score, required_fields, weight_lead_score, weight_industry, weight_company_size, weight_territory, weight_contact_info, is_active, created_by, created_at, updated_at, tenant_id) VALUES (1, 'Mid-to-Large Enterprise Integration & Management', 'This ICP targets mid-to-large enterprises across key industries that require complex integration of data, communication, and operational management solutions. Ideal for companies aiming to enhance scalability, security, and data-driven decision-making.', '["Financial Services","Technology","Manufacturing","E-commerce"]', '["201-500","501-1000","1000+"]', '["Global"]', 60, '[]', 0.25, 0.25, 0.20, 0.15, 0.15, true, 1, '2026-04-25 15:40:46', '2026-04-25 15:40:46', 1) ON CONFLICT DO NOTHING;
INSERT INTO public.icp_profiles (id, name, description, target_industries, target_company_sizes, target_territories, min_lead_score, required_fields, weight_lead_score, weight_industry, weight_company_size, weight_territory, weight_contact_info, is_active, created_by, created_at, updated_at, tenant_id) VALUES (2, 'Enterprise-Level Multisector Solutions', 'This ICP caters to large enterprises and mid-sized companies across key industries including Finance, Technology, Manufacturing, and Retail. Ideal customers seek sophisticated infrastructure, security, and management solutions to optimize operations and drive digital transformation.', '["Financial Services","Technology","Manufacturing","Retail"]', '["201-500","501-1000","1000+"]', '["Global"]', 60, '[]', 0.30, 0.25, 0.20, 0.15, 0.10, true, 1, '2026-04-26 13:11:24', '2026-04-26 13:11:24', 1) ON CONFLICT DO NOTHING;
INSERT INTO public.icp_profiles (id, name, description, target_industries, target_company_sizes, target_territories, min_lead_score, required_fields, weight_lead_score, weight_industry, weight_company_size, weight_territory, weight_contact_info, is_active, created_by, created_at, updated_at, tenant_id) VALUES (3, 'Mid-Market Enterprises in Indonesia Sector', 'Mid-sized companies in sectors such as Technology & IT Services, Finance & Banking, and Retail & Distribution, focusing on operational efficiency, compliance, and customer engagement improvement in Indonesia and Malaysia.', '["Technology & IT Services","Finance & Banking","Retail & Distribution"]', '["51-200","201-500"]', '["Indonesia","Malaysia"]', 50, '[]', 0.30, 0.25, 0.20, 0.15, 0.10, true, 1, '2026-05-19 12:32:28', '2026-05-19 12:32:28', 1) ON CONFLICT DO NOTHING;
