INSERT INTO public.lead_product_matches (id, lead_id, product_id, match_score, match_reason, is_recommended, last_matched_at, created_at, updated_at, bant_analysis, reasoning, recommended_approach, competitor_context, match_level, confidence_score, ai_provider_used, ai_model_used) VALUES (9, 57, 4, 34, 'The energy industry might have the budget, but it''s not a primary target for OceanBase, leading to uncertainty. There is potential authority access through the CEO, but it''s not certain they are directly involved in technology purchasing decisions. Lack of engagement or outlined needs suggests uncertainty about immediate purchase interest.', false, '2026-04-25 15:41:23', '2026-04-25 15:41:23', '2026-04-25 15:41:23', '{"budget":"The company size is unknown, and no budget information is available; the energy sector could have the budget, but it''s uncertain.","authority":"Only one contact with the title CEO, suggesting potential decision-making authority.","need":"The lead''s industry is Energy & Utilities, which isn''t a primary target industry; no specific pain points or needs identified.","timeline":"No recent activities or urgency signals indicating readiness to buy soon.","competitor":"No specific information about competitors; potential opportunity if OceanBase can offer unique energy solutions."}', '["The energy industry might have the budget, but it''s not a primary target for OceanBase, leading to uncertainty.","There is potential authority access through the CEO, but it''s not certain they are directly involved in technology purchasing decisions.","Lack of engagement or outlined needs suggests uncertainty about immediate purchase interest."]', 'Focus on demonstrating unique benefits of OceanBase for the energy sector, emphasizing scalability and consistency.', 'No competitor information available; positioning dependent on demonstrating superior performance for energy use cases.', 'weak', 60, NULL, 'gpt-4o') ON CONFLICT DO NOTHING;
INSERT INTO public.lead_product_matches (id, lead_id, product_id, match_score, match_reason, is_recommended, last_matched_at, created_at, updated_at, bant_analysis, reasoning, recommended_approach, competitor_context, match_level, confidence_score, ai_provider_used, ai_model_used) VALUES (10, 57, 5, 32, 'The lead is in Energy & Utilities, which might not need an omnichannel customer engagement platform aimed at industries like retail and e-commerce. The lead has a contact at a high decision-making level (CEO), but with only one contact and no recent activities, decision-making readiness is unclear. There is a lack of data regarding budget suitability for purchasing enterprise-level software.', false, '2026-04-25 15:41:27', '2026-04-25 15:41:27', '2026-04-25 15:41:27', '{"budget":"No clear signals of budget; company size and financial capacity unspecified.","authority":"Access to CEO suggests potential decision-making capability.","need":"No specific need alignment; lead is in Energy & Utilities which might not fully align with retail-focused applications.","timeline":"Low engagement signals; no indication of urgency or readiness to buy.","competitor":"No information on existing tools or competitors to evaluate displacement opportunity."}', '["The lead is in Energy & Utilities, which might not need an omnichannel customer engagement platform aimed at industries like retail and e-commerce.","The lead has a contact at a high decision-making level (CEO), but with only one contact and no recent activities, decision-making readiness is unclear.","There is a lack of data regarding budget suitability for purchasing enterprise-level software."]', 'Investigate if customer communication improvements are a strategic priority and explore any existing communication platform usage.', 'No current tools or competitors identified for strategic displacement.', 'weak', 50, NULL, 'gpt-4o') ON CONFLICT DO NOTHING;
