INSERT INTO public.lead_product_matches (id, lead_id, product_id, match_score, match_reason, is_recommended, last_matched_at, created_at, updated_at, bant_analysis, reasoning, recommended_approach, competitor_context, match_level, confidence_score, ai_provider_used, ai_model_used) VALUES (62, 61, 10, 18, 'Lead''s small size and industry do not match the product''s target market of medium to large enterprises in specific sectors. Absence of any contact information implies difficulty in reaching decision-makers within the lead organization. Lack of any engagement data or purchasing signals suggests no immediate readiness or interest in ERP solutions.', false, '2026-05-18 07:30:55', '2026-05-18 07:30:55', '2026-05-18 07:30:55', '{"budget":"Lead''s company size (1-10 employees) is significantly below the target size (201-500 employees), suggesting budget constraints compared to product cost.","authority":"No available contacts or decision-makers identified at the lead, reducing potential to reach influencers or decision-makers.","need":"Industry (Food & Beverage) doesn''t align well with product''s target industries (Manufacturing, Retail & Distribution, Finance & Banking). Lead''s needs are not clearly identified, misaligning with the product''s use cases.","timeline":"Lack of engagement and activity signals reduces assessment reliability on timeline readiness.","competitor":"No explicit signals or information regarding current ERP usage or competitive products within the lead."}', '["Lead''s small size and industry do not match the product''s target market of medium to large enterprises in specific sectors.","Absence of any contact information implies difficulty in reaching decision-makers within the lead organization.","Lack of any engagement data or purchasing signals suggests no immediate readiness or interest in ERP solutions."]', 'Focus on establishing contact to assess specific needs and project readiness, while identifying potential decision-makers.', 'No identified usage of competitor products, so the strategy should involve identifying existing tools and positioning NetSuite against gaps.', 'weak', 50, NULL, 'gpt-4o') ON CONFLICT DO NOTHING;
INSERT INTO public.lead_product_matches (id, lead_id, product_id, match_score, match_reason, is_recommended, last_matched_at, created_at, updated_at, bant_analysis, reasoning, recommended_approach, competitor_context, match_level, confidence_score, ai_provider_used, ai_model_used) VALUES (11, 57, 6, 83, 'Kebutuhan solusi keamanan IT komprehensif untuk proteksi aset digital dan compliance.', true, '2026-05-25 09:04:50', '2026-05-25 09:04:50', '2026-05-25 09:04:50', '{"budget":"The lead''s industry (Oil & Gas) typically has substantial budgets, but company size is unknown, making budget fit unclear.","authority":"Primary contact holds a CEO title, indicating decision-making authority.","need":"No probable needs or pain points identified, and the industry''s alignment with cybersecurity is not explicit.","timeline":"No recent activities or urgency level signals, suggesting a lack of immediacy in purchasing.","competitor":"No identifiable competitor signals or current tools known, limiting displacement opportunity analysis."}', '["The lead''s decision-maker status is solidified by the CEO contact, but other BANT factors are weak or inconclusive.","Industry-specific cybersecurity needs are not clearly aligned with the product''s value proposition.","Lack of engagement activities and urgent signals suggests delayed timeline for purchase."]', 'Focus on understanding potential cybersecurity needs and explore the possibility of educating the lead on the importance of IT governance.', 'No current tools or competitor products identified to strategize displacement.', 'weak', 50, NULL, 'gpt-4o') ON CONFLICT DO NOTHING;
