INSERT INTO public.lead_product_matches (id, lead_id, product_id, match_score, match_reason, is_recommended, last_matched_at, created_at, updated_at, bant_analysis, reasoning, recommended_approach, competitor_context, match_level, confidence_score, ai_provider_used, ai_model_used) VALUES (58, 61, 15, 32, 'Kebutuhan CRM omnichannel untuk customer engagement dan tracking pipeline sales.', true, '2026-05-25 09:04:50', '2026-05-25 09:04:50', '2026-05-25 09:04:50', '{"budget":"Given the company''s small size (1-10 employees), it is unlikely they have the budget to afford the product priced within IDR 100M - 300M annually.","authority":"There is no primary contact or decision-maker information available, indicating difficulty in engaging with key decision-makers.","need":"There is no indication of specific needs or pain points that align with the product\u2019s use cases, especially given the industry focus is on food processing.","timeline":"Lack of engagement signals such as activity frequency or recent buying signals suggests there is no immediate readiness to purchase.","competitor":"No competitor usage signals were identified, making it challenging to displace existing tools."}', '["The company''s small size suggests limited budget capability.","No available contacts or decision-makers impede authority identification.","The lead''s industry and lack of expressed needs do not align with the product''s primary market focus."]', 'Consider gathering more intelligence on potential needs specific to the food processing industry, identifying decision-makers and exploring scaled-back solutions.', 'No existing competitor tools or products have been identified; further exploration is needed.', 'weak', 40, NULL, 'gpt-4o') ON CONFLICT DO NOTHING;
INSERT INTO public.lead_product_matches (id, lead_id, product_id, match_score, match_reason, is_recommended, last_matched_at, created_at, updated_at, bant_analysis, reasoning, recommended_approach, competitor_context, match_level, confidence_score, ai_provider_used, ai_model_used) VALUES (50, 60, 10, 57, 'Kebutuhan ERP terintegrasi untuk manajemen keuangan, supply chain, dan operasional kompleks.', true, '2026-05-25 09:04:50', '2026-05-25 09:04:50', '2026-05-25 09:04:50', '{"budget":"The company''s size (51-200 employees) suggests possible budget constraints outside the product''s range (IDR 100M - 1B\/year) without validation.","authority":"Contact titles include ''CFO'', which is a key decision-maker, but overall decision-maker access is not confirmed due to minimal contact information.","need":"The lead''s industry (Education & Training, Higher Education) does not align with the product''s target industries (Manufacturing, Retail & Distribution, Finance & Banking), nor are there clear business problems or use cases matched.","timeline":"Low activity count and absence of urgency or purchasing signals do not indicate timeline readiness.","competitor":"No specific competitor usage signals were identified, limiting assessment of displacement opportunities."}', '["The lead is from an industry not directly targeted by the product (Education & Training vs. Manufacturing, Retail, Finance).","Recent activity implies interest, but with a single follow-up and unclear engagement, the timeline appears extended.","Financial readiness can''t be confirmed due to absence of budget validation and a smaller company size."]', 'Focus on expanding contact within the organization to identify potential needs that align with ERP solutions, and re-evaluate budget and timeline fitness through detailed discussions with decision-makers.', 'No clear competitors or existing tools are identified; exploring sectoral ERP demands could unveil indirect competitors or unmet needs.', 'weak', 55, NULL, 'gpt-4o') ON CONFLICT DO NOTHING;
