INSERT INTO public.product_questions (id, product_id, questions, ai_generated, ai_model, updated_by, created_at, updated_at) VALUES (1, 4, '[{"id":"c1a2","text":"Can you describe your current data management infrastructure and the main challenges you\u2019re facing with it?","category":"Current State","order":1},{"id":"c2b3","text":"How are you currently handling data consistency and availability across your systems?","category":"Current State","order":2},{"id":"c3c4","text":"What types of data workloads or business processes are putting the most strain on your current systems?","category":"Current State","order":3},{"id":"c4d5","text":"Have you experienced any recent incidents where data unavailability or inconsistency impacted your operations?","category":"Current State","order":4},{"id":"r1e6","text":"What are your top priorities or goals for enhancing your data infrastructure over the next 12-24 months?","category":"Requirements","order":5},{"id":"r2f7","text":"Which applications or processes require the highest level of data reliability and performance in your organization?","category":"Requirements","order":6},{"id":"r3g8","text":"Are there any regulatory or compliance requirements influencing your data management choices?","category":"Requirements","order":7},{"id":"r4h9","text":"What kind of scalability do you expect your data systems to support as your business grows?","category":"Requirements","order":8},{"id":"b1i0","text":"Have you established a budget range for your data infrastructure improvements or database solutions?","category":"Budget & Timeline","order":9},{"id":"b2j1","text":"What would a successful investment in a new database solution look like for your business?","category":"Budget & Timeline","order":10},{"id":"b3k2","text":"Is there a preferred time frame for implementing a new solution, or any key business events driving your timeline?","category":"Budget & Timeline","order":11},{"id":"d1l3","text":"Who are the key stakeholders involved in decisions about your company\u2019s data infrastructure?","category":"Decision Process","order":12},{"id":"d2m4","text":"What does your internal evaluation or procurement process for technology solutions typically involve?","category":"Decision Process","order":13},{"id":"d3n5","text":"What criteria will be most important to your team when selecting a new database solution?","category":"Decision Process","order":14},{"id":"t1o6","text":"What types of database systems are currently in use in your environment (e.g., Oracle, MongoDB, etc.)?","category":"Technical Fit","order":15},{"id":"t2p7","text":"Are there any technical constraints or preferred environments (cloud, on-premise, hybrid) for your data infrastructure?","category":"Technical Fit","order":16},{"id":"t3q8","text":"Can you share any pain points your IT team faces with integrating data across different applications or locations?","category":"Technical Fit","order":17},{"id":"co1r9","text":"What other database solutions or vendors are you currently considering or evaluating?","category":"Competition","order":18}]', true, 'gpt-4.1', 2, '2026-05-20 08:24:54', '2026-05-20 08:24:54') ON CONFLICT DO NOTHING;
INSERT INTO public.product_questions (id, product_id, questions, ai_generated, ai_model, updated_by, created_at, updated_at) VALUES (2, 24, '[{"id":"cs1","text":"Can you walk me through how your teams currently collaborate and share information across different locations?","category":"Current State","order":1},{"id":"cs2","text":"What are some challenges you\u2019re facing with your existing productivity and collaboration tools?","category":"Current State","order":2},{"id":"cs3","text":"How do fragmented processes impact your team\u2019s productivity or business operations today?","category":"Current State","order":3},{"id":"cs4","text":"How are operational performance and technology adoption currently tracked and measured in your business?","category":"Current State","order":4},{"id":"req1","text":"What are your top priorities when it comes to improving collaboration and operational efficiency?","category":"Requirements","order":5},{"id":"req2","text":"Are there specific features or integrations you require in a collaboration suite?","category":"Requirements","order":6},{"id":"req3","text":"What outcomes would signal a successful implementation of a new collaboration platform for your organization?","category":"Requirements","order":7},{"id":"req4","text":"How important is scalability and ease of use when selecting new technology solutions?","category":"Requirements","order":8},{"id":"bud1","text":"Can you share how your organization typically allocates budget for IT or productivity tools?","category":"Budget & Timeline","order":9},{"id":"bud2","text":"Do you have a defined budget range or planned investment for this project?","category":"Budget & Timeline","order":10},{"id":"bud3","text":"What timeline are you considering for exploring and potentially deploying a new solution?","category":"Budget & Timeline","order":11},{"id":"dp1","text":"Who are the key stakeholders involved in evaluating and approving new technology solutions?","category":"Decision Process","order":12},{"id":"dp2","text":"How does your decision-making process typically work for adopting new digital tools or platforms?","category":"Decision Process","order":13},{"id":"dp3","text":"What factors are most important to leadership when choosing a collaboration software?","category":"Decision Process","order":14},{"id":"tech1","text":"Are you currently using any Google products or cloud-based tools in your organization?","category":"Technical Fit","order":15},{"id":"tech2","text":"What are the key security or compliance requirements your business must adhere to when adopting cloud solutions?","category":"Technical Fit","order":16},{"id":"tech3","text":"How would a new collaboration tool need to integrate with your existing systems or workflows?","category":"Technical Fit","order":17},{"id":"comp1","text":"What other collaboration or productivity platforms are you currently evaluating or using?","category":"Competition","order":18},{"id":"comp2","text":"Are there specific reasons you are considering or moving away from other solutions like Microsoft 365 or Zoho?","category":"Competition","order":19},{"id":"comp3","text":"What have you liked or disliked about your experience with other solutions you\u2019ve tried so far?","category":"Competition","order":20}]', true, 'gpt-4.1', 1, '2026-05-20 09:03:44', '2026-05-20 09:03:44') ON CONFLICT DO NOTHING;
INSERT INTO public.product_questions (id, product_id, questions, ai_generated, ai_model, updated_by, created_at, updated_at) VALUES (3, 7, '[{"id":"q1a2b3","text":"Can you describe your current budgeting and forecasting process?","category":"Current State","order":1},{"id":"q2b3c4","text":"What are the main challenges or pain points you face with your existing financial planning tools?","category":"Current State","order":2},{"id":"q3c4d5","text":"How do you currently access and utilize real-time data insights for business decisions?","category":"Current State","order":3},{"id":"q4d5e6","text":"How effective do you feel your current systems are in supporting your performance management and KPI tracking?","category":"Current State","order":4},{"id":"q5e6f7","text":"What improvements are you looking for in your budgeting, forecasting, or analytics processes?","category":"Requirements","order":5},{"id":"q6f7g8","text":"What specific business outcomes are you hoping to achieve with an enhanced planning and analytics platform?","category":"Requirements","order":6},{"id":"q7g8h9","text":"Are there any critical reports or dashboards that you need but currently lack access to?","category":"Requirements","order":7},{"id":"q8h9i0","text":"How important is integration with your existing IT systems or ERP solutions?","category":"Requirements","order":8},{"id":"q9i0j1","text":"What is your planned budget range for a new planning and analytics solution?","category":"Budget & Timeline","order":9},{"id":"q0j1k2","text":"Do you have a timeline in mind for when you\u2019d like to implement a new platform?","category":"Budget & Timeline","order":10},{"id":"q1k2l3","text":"Are there any upcoming business events or initiatives driving the need for a new solution?","category":"Budget & Timeline","order":11},{"id":"q2l3m4","text":"Who will be involved in the evaluation and decision-making process for this project?","category":"Decision Process","order":12},{"id":"q3m4n5","text":"What roles do Finance, IT, and Business teams play in selecting new analytics platforms?","category":"Decision Process","order":13},{"id":"q4n5o6","text":"Are there any key decision criteria that must be met to move forward with a solution?","category":"Decision Process","order":14},{"id":"q5o6p7","text":"Could you describe your company\u2019s current IT landscape\u2014what systems and data sources do you use most often?","category":"Technical Fit","order":15},{"id":"q6p7q8","text":"What are your integration requirements with core business applications or databases?","category":"Technical Fit","order":16},{"id":"q7q8r9","text":"Are there any security or compliance considerations we should be aware of for your region or industry?","category":"Technical Fit","order":17},{"id":"q8r9s0","text":"Have you evaluated other planning and analytics platforms recently? If so, which ones and what did you think?","category":"Competition","order":18},{"id":"q9s0t1","text":"What stood out to you\u2014positively or negatively\u2014about competitors like IBM Planning Analytics, Anaplan, or others?","category":"Competition","order":19}]', true, 'gpt-4.1', 1, '2026-05-20 09:10:18', '2026-05-20 09:10:18') ON CONFLICT DO NOTHING;
